import { useContext } from "react";
import AuthContext from "../auth";
import MUIErrorModal from "./MUIErrorModal";
import Copyright from "./Copyright";

import Avatar from "@mui/material/Avatar";
import Box from "@mui/material/Box";
import Button from "@mui/material/Button";
import Container from "@mui/material/Container";
import CssBaseline from "@mui/material/CssBaseline";
import Grid from "@mui/material/Grid";
import Link from "@mui/material/Link";
import LockOutlinedIcon from "@mui/icons-material/LockOutlined";
import TextField from "@mui/material/TextField";
import Typography from "@mui/material/Typography";
import HighlightOffIcon from "@mui/icons-material/HighlightOff";

import { useState } from "react";

const defaultAvatar =
  "https://static.vecteezy.com/system/resources/thumbnails/009/292/244/small/default-avatar-icon-of-social-media-user-vector.jpg";
export default function CreateAccountScreen() {
  const { auth } = useContext(AuthContext);
  const [formData, setFormData] = useState({
    userName: "",
    email: "",
    password: "",
    passwordConfirm: "",
    avatarUrl: "",
  });

  const handleSubmit = (event) => {
    event.preventDefault();
    auth.registerUser(
      formData.userName,
      formData.email,
      formData.password,
      formData.passwordConfirm,
      formData.avatarUrl
    );
  };

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleClear = (field) => {
    setFormData({ ...formData, [field]: "" });
  };

  const handleAvatarChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        setFormData({ ...formData, avatarUrl: reader.result });
      };
      reader.readAsDataURL(file);
    }
  };

  const canComplete = () => {
    const requiredFieldsFilled =
      formData.userName.trim() !== "" &&
      formData.email.trim() !== "" &&
      formData.password.trim() !== "" &&
      formData.passwordConfirm.trim() !== "";

    if (!requiredFieldsFilled) {
      return false;
    }

    if (formData.password !== formData.passwordConfirm) {
      return false;
    }

    return true;
  };

  let modalJSX = "";
  console.log(auth);
  if (auth.errorMessage !== null) {
    modalJSX = <MUIErrorModal />;
  }
  console.log(modalJSX);

  return (
    <Container component="main" maxWidth="xs">
      <CssBaseline />
      <Box
        sx={{
          marginTop: 8,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
        }}
      >
        <LockOutlinedIcon sx={{ fontSize: 50 }} />

        <Typography component="h1" variant="h4" sx={{ mt: 3 }}>
          Create Account
        </Typography>

        <Box
          sx={{
            position: "absolute",
            top: 315,
            left: "32%",
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
          }}
        >
          <Avatar
            alt="User Avatar"
            src={formData.avatarUrl || defaultAvatar}
            sx={{
              width: 60,
              height: 60,
              mb: 0.5,
            }}
          />
          <Button
            type="submit"
            variant="contained"
            sx={{
              bgcolor: "black",
              fontSize: "0.8rem",
              padding: "2px 8px",
            }}
            onClick={() =>
              document.getElementById("avatar-upload-input").click()
            }
          >
            Select
          </Button>
          <input
            accept="image/*"
            style={{ display: "none" }}
            id="avatar-upload-input"
            type="file"
            onChange={handleAvatarChange}
          />
        </Box>
        <Box component="form" noValidate onSubmit={handleSubmit} sx={{ mt: 6 }}>
          <Grid container spacing={4}>
            <Grid item xs={12} sx={{ position: "relative" }}>
              <TextField
                autoComplete="fname"
                name="userName"
                required
                fullWidth
                id="userName"
                label="User Name"
                onChange={handleChange}
                value={formData.userName}
                autoFocus
                variant="filled"
                sx={{ bgcolor: "rgb(216, 240, 247)" }}
              />
              <HighlightOffIcon
                sx={{
                  position: "absolute",
                  right: 5,
                  top: "60%",
                  transform: "translateY(-50%)",
                  cursor: "pointer",
                }}
                onClick={() => handleClear("userName")}
              />
            </Grid>
            <Grid item xs={12} sx={{ position: "relative" }}>
              <TextField
                required
                fullWidth
                id="email"
                label="Email"
                name="email"
                autoComplete="email"
                value={formData.email}
                onChange={handleChange}
                variant="filled"
                sx={{ bgcolor: "rgb(216, 240, 247)" }}
              />
              <HighlightOffIcon
                sx={{
                  position: "absolute",
                  right: 5,
                  top: "60%",
                  transform: "translateY(-50%)",
                  cursor: "pointer",
                }}
                onClick={() => handleClear("email")}
              />
            </Grid>
            <Grid item xs={12} sx={{ position: "relative" }}>
              <TextField
                required
                fullWidth
                name="password"
                label="Password"
                type="password"
                id="password"
                autoComplete="new-password"
                value={formData.password}
                onChange={handleChange}
                variant="filled"
                sx={{ bgcolor: "rgb(216, 240, 247)" }}
              />
              <HighlightOffIcon
                sx={{
                  position: "absolute",
                  right: 5,
                  top: "60%",
                  transform: "translateY(-50%)",
                  cursor: "pointer",
                }}
                onClick={() => handleClear("password")}
              />
            </Grid>
            <Grid item xs={12} sx={{ position: "relative" }}>
              <TextField
                required
                fullWidth
                name="passwordConfirm"
                label="Password Confirm"
                type="password"
                id="passwordConfirm"
                autoComplete="new-password"
                value={formData.passwordConfirm}
                onChange={handleChange}
                variant="filled"
                sx={{ bgcolor: "rgb(216, 240, 247)" }}
              />
              <HighlightOffIcon
                sx={{
                  position: "absolute",
                  right: 5,
                  top: "60%",
                  transform: "translateY(-50%)",
                  cursor: "pointer",
                }}
                onClick={() => handleClear("passwordConfirm")}
              />
            </Grid>
          </Grid>
          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 4, mb: 2, bgcolor: "black" }}
            disabled={!canComplete()}
          >
            Create Account
          </Button>
          <Grid container justifyContent="flex-end">
            <Grid item>
              <Link href="/login/" variant="body2">
                Already have an account? Sign in
              </Link>
            </Grid>
          </Grid>
        </Box>
      </Box>
      <Copyright sx={{ mt: 7 }} />
      {modalJSX}
    </Container>
  );
}
